import{_ as s,o as t,c as i,a2 as e}from"./chunks/framework.BFVZdVmd.js";const k=JSON.parse('{"title":"SQL 优化与索引","description":"","frontmatter":{},"headers":[],"relativePath":"practice/sql-optimization.md","filePath":"practice/sql-optimization.md","lastUpdated":null}'),n={name:"practice/sql-optimization.md"};function l(p,a,d,o,h,c){return t(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="sql-优化与索引" tabindex="-1">SQL 优化与索引 <a class="header-anchor" href="#sql-优化与索引" aria-label="Permalink to &quot;SQL 优化与索引&quot;">​</a></h1><blockquote><p>本页内容为新增的工程实践部分，不来自原《Spring 技术套件》文档。</p></blockquote><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p><a href="/my-docs/storage/">数据存储</a>栏目讲了&quot;用 MySQL + MyBatis-Plus&quot;，本页讲&quot;怎么用好&quot;——索引原理、SQL 优化、事务隔离和锁，是后端面试和实战的高频内容。</p><h2 id="索引原理" tabindex="-1">索引原理 <a class="header-anchor" href="#索引原理" aria-label="Permalink to &quot;索引原理&quot;">​</a></h2><p>MySQL（InnoDB）索引基于 B+ 树：</p><ul><li>数据按主键有序组织成 B+ 树（聚簇索引），叶子节点存整行数据。</li><li>普通索引（二级索引）叶子节点存主键值，查非索引列需要&quot;回表&quot;。</li><li>B+ 树高度通常 3~4 层，意味着一次查询最多几次磁盘 IO。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>覆盖索引：查询列都在索引中，无需回表，性能最好</span></span>
<span class="line"><span>最左前缀：联合索引 (a,b,c) 能命中 a / a,b / a,b,c，但命中不了 b 或 c</span></span></code></pre></div><h2 id="索引失效的常见场景" tabindex="-1">索引失效的常见场景 <a class="header-anchor" href="#索引失效的常见场景" aria-label="Permalink to &quot;索引失效的常见场景&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>对索引列做函数 / 运算：WHERE YEAR(create_time) = 2026</span></span>
<span class="line"><span>隐式类型转换：字符串列用数字查 WHERE phone = 138...</span></span>
<span class="line"><span>前导模糊查询：LIKE &#39;%abc&#39;</span></span>
<span class="line"><span>联合索引不满足最左前缀</span></span>
<span class="line"><span>OR 连接非索引列</span></span></code></pre></div><h2 id="sql-优化思路" tabindex="-1">SQL 优化思路 <a class="header-anchor" href="#sql-优化思路" aria-label="Permalink to &quot;SQL 优化思路&quot;">​</a></h2><p>排查慢查询的标准流程：</p><ol><li>开启慢查询日志，定位慢 SQL。</li><li>用 <code>EXPLAIN</code> 看执行计划，重点关注 <code>type</code>、<code>key</code>、<code>rows</code>、<code>Extra</code>。</li><li><code>type</code> 至少要到 <code>range</code>，避免 <code>ALL</code>（全表扫描）。</li><li><code>Extra</code> 出现 <code>Using filesort</code> / <code>Using temporary</code> 通常需要优化。</li></ol><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EXPLAIN </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>常见优化手段：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>加合适的索引（联合索引、覆盖索引）</span></span>
<span class="line"><span>只查需要的列，避免 SELECT *</span></span>
<span class="line"><span>大分页用游标 / 延迟关联，避免 LIMIT 1000000, 20</span></span>
<span class="line"><span>拆分大事务、大 SQL</span></span>
<span class="line"><span>合理使用缓存，减少数据库压力</span></span></code></pre></div><h2 id="事务隔离级别" tabindex="-1">事务隔离级别 <a class="header-anchor" href="#事务隔离级别" aria-label="Permalink to &quot;事务隔离级别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>级别</th><th>脏读</th><th>不可重复读</th><th>幻读</th></tr></thead><tbody><tr><td>读未提交</td><td>可能</td><td>可能</td><td>可能</td></tr><tr><td>读已提交</td><td>不会</td><td>可能</td><td>可能</td></tr><tr><td>可重复读（MySQL 默认）</td><td>不会</td><td>不会</td><td>基本不会（间隙锁）</td></tr><tr><td>串行化</td><td>不会</td><td>不会</td><td>不会</td></tr></tbody></table><p>InnoDB 在可重复读级别通过 MVCC + 间隙锁，基本解决了幻读。</p><h2 id="锁" tabindex="-1">锁 <a class="header-anchor" href="#锁" aria-label="Permalink to &quot;锁&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>行锁    InnoDB 默认，基于索引；查不到索引会退化成表锁</span></span>
<span class="line"><span>间隙锁  锁住索引区间，防止幻读</span></span>
<span class="line"><span>意向锁  表级，标记表中有行锁</span></span>
<span class="line"><span>乐观锁  靠版本号 / CAS，适合冲突少的场景（MyBatis-Plus @Version）</span></span>
<span class="line"><span>悲观锁  SELECT ... FOR UPDATE，适合冲突多的场景</span></span></code></pre></div><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>索引不是越多越好，写多读少的表要控制索引数量。</li><li>高并发更新场景优先考虑乐观锁，减少锁等待。</li><li>单表数据量过大（千万级以上）再考虑<a href="/my-docs/storage/sharding">分库分表</a>，不要过早优化。</li><li>复杂查询、聚合分析迁移到 <a href="/my-docs/storage/elasticsearch">Elasticsearch</a> 或分析型数据库，不要硬压在 MySQL 上。</li></ul>`,23)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
